let currentEditClientId = null;

// open edit screen
document.addEventListener('click',function(e){
    let btn = e.target.closest('[data-edit-client]');
    if(btn){
        currentEditClientId = btn.dataset.editClient;

        fetch(`${API_URL}/clients/${currentEditClientId}`)
        .then(r=>r.json())
        .then(c=>{
            let inputs = document.querySelectorAll('[data-screen="edit-client"] input');
            inputs[0].value = c.name;
            inputs[1].value = c.phone;
            showScreen('edit-client');
        });
    }
});

// update client
let updateBtn = document.querySelector('[data-update-client]');
if(updateBtn){
    updateBtn.addEventListener('click',()=>{
        let inputs = document.querySelectorAll('[data-screen="edit-client"] input');
        let name = inputs[0].value;
        let phone = inputs[1].value;

        fetch(`${API_URL}/clients/${currentEditClientId}`,{
            method:'PATCH',
            headers:{'Content-Type':'application/json'},
            body:JSON.stringify({name,phone})
        })
        .then(()=>{
            showToast('Client updated','success');
            loadClients();
            showScreen('clients-list');
        });
    });
}
